input.command:
for f in /tmp/regie_solution/Workflows/*.json; do echo "=== $(basename $f) ==="; python3 -c "
import json
d=json.load(open('$f'))
defn=d.get('properties',{}).get('definition',{})
actions=defn.get('actions',{})
def walk(a, path=''):
    for k,v in a.items():
        if isinstance(v,dict):
            t = v.get('type','')
            inputs = v.get('inputs',{})
            host = inputs.get('host',{}) if isinstance(inputs,dict) else {}
            op = host.get('operationId') if isinstance(host,dict) else None
            ent = (inputs.get('parameters',{}) or {}).get('entityName') if isinstance(inputs,dict) else None
            if op or ent or t in ('OpenApiConnection','ApiConnection'):
                print(f'  {path}/{k}: type={t} op={op} entity={ent}')
            if 'actions' in v: walk(v['actions'], path+'/'+k)
            if 'else' in v and isinstance(v['else'],dict) and 'actions' in v['else']: walk(v['else']['actions'], path+'/'+k+'/else')
            if 'cases' in v:
                for ck,cv in v['cases'].items():
                    if 'actions' in cv: walk(cv['actions'], path+'/'+k+'/cases/'+ck)
            if 'default' in v and isinstance(v['default'],dict) and 'actions' in v['default']: walk(v['default']['actions'], path+'/'+k+'/default')
walk(actions)
"; done 2>&1 | head -120
